import os

def main():
    # Define a ConfigParserWithComments class that preserves comments
    class ConfigParserWithComments(configparser.ConfigParser):
        def __init__(self, *args, **kwargs):
            super().__init__(*args, **kwargs)
            self._section_comments = {}
            self._option_comments = {}

        def add_section_comment(self, section, comment):
            """Add a comment line before a section"""
            if section not in self._section_comments:
                self._section_comments[section] = []
            self._section_comments[section].append(comment)

        def add_option_comment(self, section, option, comment):
            """Add a comment line before an option"""
            key = (section, option)
            if key not in self._option_comments:
                self._option_comments[key] = []
            self._option_comments[key].append(comment)

    def serialize(config, path):
        with open(path, 'w', encoding='utf-8') as f:
            # Write default section if present
            if config.defaults():
                f.write('[DEFAULT]\n')
                for key, value in config.defaults().items():
                    if ':' in value or '#' in value or ';' in value or value.startswith(' ') or value.endswith(' ') or '"' in value:
                        f.write(f'{key} = "{value}"\n')
                    else:
                        f.write(f'{key} = {value}\n')
                f.write('\n')

            for section in config.sections():
                # Write section comments
                if hasattr(config, '_section_comments') and section in config._section_comments:
                    for comment in config._section_comments[section]:
                        f.write(comment + '\n')

                f.write(f'[{section}]\n')
                for option in config.options(section):
                    value = config.get(section, option)
                    # Write option comments
                    key = (section, option)
                    if hasattr(config, '_option_comments') and key in config._option_comments:
                        for comment in config._option_comments[key]:
                            f.write(comment + '\n')
                    # Handle special characters - need proper INI escaping
                    # ConfigParser.write() handles this, but we're doing custom writing
                    if ':' in value or '#' in value or ';' in value or value.startswith(' ') or value.endswith(' ') or '"' in value or "'" in value:
                        # Escape double quotes inside the value
                        escaped_value = value.replace('"', '\\"')
                        f.write(f'{option} = "{escaped_value}"\n')
                    else:
                        f.write(f'{option} = {value}\n')
                f.write('\n')

    # Create a configuration with two sections and options
    config = ConfigParserWithComments()
    config['General'] = {
        'version': '1.0',
        'enabled': 'yes'
    }
    config['User'] = {
        'name': 'Alice',
        'email': 'alice@example.com'
    }

    # Add some comments
    config.add_section_comment('General', '# General settings')
    config.add_option_comment('General', 'version', '; Version number')
    config.add_option_comment('User', 'name', '# User full name')

    # Define the output file path
    path = 'test_config.ini'

    # Save the configuration to disk
    serialize(config, path)

    # Verify that the file was created and print its contents
    if os.path.exists(path):
        with open(path, 'r') as f:
            content = f.read()
        print('Configuration file content:')
        print(content)
    else:
        print('Failed to create configuration file.')

if __name__ == '__main__':
